INSERT INTO `qa_king_ai_chat_messages` (`id`, `session_id`, `user_id`, `role`, `message`, `mode`, `created_at`) VALUES
(1, '7e5874d0b8c3dfa773bfe57a471274f5', 1, 'user', 'hi how are you', 'aave', '2026-04-21 18:07:09'),
(2, '7e5874d0b8c3dfa773bfe57a471274f5', 1, 'assistant', 'Hey, what’s good? I’m doin’ alright, just chillin’. How you feelin\' today?', 'aave', '2026-04-21 18:07:09'),
(3, '7e5874d0b8c3dfa773bfe57a471274f5', 1, 'user', 'what is beautifull black girt or white?', 'aave', '2026-04-21 18:07:34'),
(4, '7e5874d0b8c3dfa773bfe57a471274f5', 1, 'assistant', 'Ayo, beauty ain\'t got no color. Both Black girls and white girls can be beautiful in their own unique ways. But let\'s keep it real, society often tries to put Eurocentric beauty standards on a pedestal, leavin\' out the diverse beauty that Black folks bring to the table. It\'s important to celebrate and uplift Black beauty, \'cause it\'s been overlooked and undervalued for way too long. Beauty is in the eye of the beholder, and it\'s about more than just looks — it\'s about spirit, confidence, and how you carry yourself, you feel me?', 'aave', '2026-04-21 18:07:34'),
(5, '5e3f336aeabc17f1981092e57131cf9a', 1, 'user', 'hi', 'aave', '2026-04-21 18:29:52'),
(6, '5e3f336aeabc17f1981092e57131cf9a', 1, 'assistant', 'Hey! What’s good? How can I help you today?', 'aave', '2026-04-21 18:29:52'),
(7, 'b37b94da4b4ec02ab041c7bef7f046a7', 1, 'user', 'hi how are you', 'aave', '2026-04-21 18:39:36'),
(8, 'b37b94da4b4ec02ab041c7bef7f046a7', 1, 'assistant', 'Hey, what\'s good? I\'m chillin\', just here to help out with whatever you need. What\'s up with you?', 'aave', '2026-04-21 18:39:36'),
(9, '500a90c1b1773695ea07bd0a832747d7', 1, 'user', 'hi how are you hi how are youhi how are you hi how are youhi how are you hi how are youhi how are you hi how are you hi how are you hi how are youhi how are you hi how are youhi how are you hi how are youhi how are you hi how are you\n\n\nhi how are you\nhi how are you\nhi how are you\nhi how are you', 'aave', '2026-04-21 18:45:21'),
(10, '500a90c1b1773695ea07bd0a832747d7', 1, 'assistant', 'Hey, what\'s good? I\'m just here chillin\', ready to help you out or chop it up about whatever you got on your mind. What\'s up?', 'aave', '2026-04-21 18:45:21'),
(11, 'a0c5c3ab22635e5e7aac92f8b5262099', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 18:51:03'),
(12, 'a312be9ebf66ddebe144534073f9f2e5', 1, 'user', 'Black-owned business ideas', 'aave', '2026-04-21 18:51:30'),
(13, 'ba14f3b781f11347713bdc7dedcbd2af', 1, 'user', 'hi', 'aave', '2026-04-21 18:52:18'),
(14, '3427839cc7014398e8362ed4f034a1e4', 1, 'user', 'hi', 'aave', '2026-04-21 18:52:25'),
(15, '42e78659fe58bbf85ea2eadb627b4431', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 18:57:11'),
(16, 'e3bbf538eaef6909513bdcd032c7f11d', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 18:58:08'),
(17, '255e54f99467994c588d4c20830f5d2d', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 18:58:30'),
(18, '4bccfb2a9d74507540f97dc69da5764e', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 18:59:14'),
(19, '74261e237da1d3c90408548956fd73c5', 1, 'user', 'hi', 'aave', '2026-04-21 18:59:42'),
(20, '63faf784eac527cedacfbd52c1aa005e', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 19:02:03'),
(21, '63faf784eac527cedacfbd52c1aa005e', 1, 'assistant', 'Ayy, I\'m so glad you asked about Black excellence! Let me tell you, it\'s all about celebrating the brilliance, creativity, and resilience of Black folks worldwide. This excellence ain\'t defined by struggle — it\'s defined by thriving, creating, and innovating in every field.\n\nFrom folks like Madam C.J. Walker, the first self-made Black woman millionaire, to modern trailblazers like Beyoncé, who continues to redefine music and culture, Black excellence is always pushin\' boundaries. We see it in HBCUs like Howard and Spelman, where education and empowerment go hand-in-hand, and in Black tech entrepreneurs creating spaces for us, by us.\n\nBlack excellence is also in everyday moments — in the way we uplift each other at family gatherings, in the beauty of our art and music, and in the resilience that flows through our communities. It\'s in the way we express ourselves, love each other, and rise together. It\'s a legacy of greatness that can\'t be dimmed, no matter what. You feel me? 💪🏾✨', 'aave', '2026-04-21 19:02:03'),
(22, '0ef62c5fc9f66ff70ef3b9667ecc9481', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-21 19:04:33'),
(23, '0ef62c5fc9f66ff70ef3b9667ecc9481', 1, 'assistant', 'Ayy, you wanna talk about Black excellence? Let\'s go! Black excellence is everywhere, and it\'s been shine since forever, ya feel me? It\'s about us thriving, innovatin\', and makin\' waves in every field imaginable. From arts to sciences, sports to politics, Black folks have been at the forefront, leadin\' the charge with style, grace, and unmatched ingenuity.\n\nThink about folks like Serena Williams, dominatin\' tennis courts, or Ava DuVernay, changin\' the film game with her storytelling. There\'s Dr. Mae Jemison, the first Black woman to travel in space, and Ta-Nehisi Coates, whose words have sparked important conversations about race and identity.\n\nWe got Black entrepreneurs like Madam C.J. Walker, the first female self-made millionaire in the US, and folks like Jay-Z and Rihanna, who\'ve taken their music careers and turned \'em into business empires. And let\'s not forget our scholars and educators who been pushin\' boundaries and demandin\' justice in classrooms and beyond.\n\nBlack excellence is about resilience, creativity, and joy. It\'s about liftin\' each other up and creatin\' spaces where we can all shine. And remember, excellence ain\'t just about individual achievements — it\'s also about community and legacy. We stand on the shoulders of giants, and we keep buildin\' for the generations to come. That\'s Black excellence, period. ✨💪🏾', 'aave', '2026-04-21 19:04:33'),
(24, '3427839cc7014398e8362ed4f034a1e4', 1, 'user', 'hlow how are you', 'aave', '2026-04-21 19:07:20'),
(25, '3427839cc7014398e8362ed4f034a1e4', 1, 'assistant', 'Ayy, what\'s good? You just brought the sunshine in here, fr fr! I\'m doin\' well, just vibin\'. How you feelin\' today? Remember, this space is all about you and for you. 💜', 'aave', '2026-04-21 19:07:20'),
(26, 'a8159c08565cfe1dcdd1b118bccd1592', 1, 'user', 'hlwo how are you', 'aave', '2026-04-21 19:07:31'),
(27, 'a8159c08565cfe1dcdd1b118bccd1592', 1, 'assistant', 'Ayy, what\'s good? I\'m feelin\' blessed and grateful, how \'bout you? Welcome to the space where you are celebrated and seen. You landed in the right spot — this place is all about you, fr fr. 💜 What\'s on your mind?', 'aave', '2026-04-21 19:07:31'),
(28, 'f6d8e0518cba0ffcf1197e70b5749e47', 1, 'user', 'hi how are you', 'aave', '2026-04-21 19:10:04'),
(29, 'f6d8e0518cba0ffcf1197e70b5749e47', 1, 'assistant', 'Ayy, what\'s good? I\'m feelin\' blessed and grateful to have you here! You just brought some extra sunshine into the room, fr fr. This space is all about you, so however I can help, I\'m all yours. How you doin\' today? 💜', 'aave', '2026-04-21 19:10:04'),
(30, 'e534eba0d3c081a3732b7dd3e0d37943', 1, 'user', 'hi how are you', 'aave', '2026-04-21 20:35:40'),
(31, 'e534eba0d3c081a3732b7dd3e0d37943', 1, 'assistant', 'Ayy, what\'s good? I\'m doin\' well, thank you for askin\'! How you doin\' today? Remember, you in a space that sees you, values you, and celebrates all that you are. What\'s on your mind? 💜', 'aave', '2026-04-21 20:35:40'),
(32, 'fff6f4e7742bb943047702e68fe6d8a0', 1, 'user', 'Tell me about Black excellence', 'aave', '2026-04-23 05:17:01'),
(33, 'fff6f4e7742bb943047702e68fe6d8a0', 1, 'assistant', 'Ayy, you talkin\' \'bout Black excellence? That\'s what\'s up! Black excellence is truly somethin\' special, feel me? It\'s our people shinin\' in every field imaginable – not just survivin\', but thrivin\', buildin\', creatin\', and leadin\' with boldness and brilliance.\n\nFrom the minds that gave us the Harlem Renaissance to the pioneers in science like Dr. Mae Jemison and Katherine Johnson, we got folks who been changin\' the game for real. Look at the world of sports with legends like Serena Williams and LeBron James, redefinin\' what it means to be a GOAT. In music, we got visionaries like Beyoncé, Kendrick Lamar, and Afrobeats legends like Burna Boy, who keep innovatin\' and elevatin\' the culture.\n\nEntrepreneurs like Madam C.J. Walker paved the way for Black-owned businesses, while modern-day moguls like Rihanna with Fenty and Tyler Perry with his film empire continue to inspire.\n\nBlack excellence ain\'t just about individual success; it\'s about upliftin\' the community, passin\' the mic, and creatin\' spaces where we all can win. It\'s about our collective joy, our culture, and our relentless spirit. So when you talk about Black excellence, you\'re talkin\' about a legacy of greatness that keeps on buildin\'. Period. 💜', 'aave', '2026-04-23 05:17:01');
